# provider/tests/pact/provider_states.py
# Provider state handlers set up test data before each pact interaction

from myapp.database import db
from myapp.search_index import search_index

PROVIDER_STATES = {
    "the search index contains IPCC documents": setup_ipcc_documents,
    "the search index is empty": setup_empty_index,
    "the search service is rate limited": setup_rate_limit_condition,
}

def setup_ipcc_documents():
    search_index.clear()
    search_index.index([
        {
            "id": "ipcc-ar6-sealevel",
            "title": "IPCC AR6 Sea Level Rise",
            "url": "https://example.com/ipcc-ar6",
            "body": "Sea levels are projected to rise by 0.3-1.0m by 2100...",
        }
    ])

def setup_empty_index():
    search_index.clear()

def setup_rate_limit_condition():
    """Configure the test service to return 429 for the next request."""
    search_index.set_rate_limit_mode(True)
